const exec = $input.first().json.execution || {};
const wfName = exec.workflowData?.name || 'Unknown';
const errorMsg = exec.error?.message || 'No error message';
const nodeName = exec.error?.node?.name || 'Unknown node';
const execId = exec.id || 'unknown';
const execUrl = $vars.N8N_HOST + '/workflow/m3BWxESfNCs1ccws/executions/' + execId;
const ts = new Date().toISOString();

return [{
  json: {
    workflow_name: wfName,
    error_message: errorMsg.slice(0, 500),
    node_name: nodeName,
    execution_id: execId,
    execution_url: execUrl,
    timestamp: ts,
    source: 'gateway_error_handler'
  }
}];
